<?php
use App\Http\Controllers\AuthController;use App\Http\Controllers\HomeController;use App\Http\Controllers\GameController;use App\Http\Controllers\OrderController;use App\Http\Controllers\WalletController;use App\Http\Controllers\PaymentController;use App\Http\Controllers\Admin\DashboardController;use App\Http\Controllers\Admin\GameController as AdminGameController;use App\Http\Controllers\Admin\PackageController;use App\Http\Controllers\Admin\ProviderController;use App\Http\Controllers\Admin\BannerController;use App\Http\Controllers\Admin\VideoController;use App\Http\Controllers\Admin\OrderController as AdminOrderController;use App\Http\Controllers\Admin\LogController;use Illuminate\Support\Facades\Route;
Route::get('/',[HomeController::class,'index'])->name('home');
Route::middleware('guest')->group(function(){Route::get('/login',[AuthController::class,'loginForm'])->name('login');Route::post('/login',[AuthController::class,'login'])->name('login.post');Route::get('/register',[AuthController::class,'registerForm'])->name('register');Route::post('/register',[AuthController::class,'register'])->name('register.post');});
Route::post('/logout',[AuthController::class,'logout'])->middleware('auth')->name('logout');
Route::middleware('auth')->group(function(){Route::get('/game/{game:slug}',[GameController::class,'show'])->name('game.show');Route::post('/order',[OrderController::class,'store'])->name('order.store');Route::get('/orders',[OrderController::class,'index'])->name('orders.index');Route::get('/wallet',[WalletController::class,'index'])->name('wallet.index');Route::post('/wallet/razorpay',[PaymentController::class,'walletOrder'])->name('wallet.razorpay');Route::get('/payment/direct',[PaymentController::class,'directOrder'])->name('payment.direct');Route::post('/payment/verify',[PaymentController::class,'verify'])->name('payment.verify');});
Route::prefix('admin')->name('admin.')->middleware(['auth','admin'])->group(function(){Route::get('/',[DashboardController::class,'index'])->name('dashboard');Route::resource('games',AdminGameController::class)->except(['show','destroy']);Route::resource('packages',PackageController::class)->except(['show','destroy']);Route::resource('providers',ProviderController::class)->except(['show','destroy']);Route::resource('banners',BannerController::class)->except(['show','destroy']);Route::resource('videos',VideoController::class)->except(['show','destroy']);Route::get('orders',[AdminOrderController::class,'index'])->name('orders.index');Route::get('logs',[LogController::class,'index'])->name('logs.index');Route::post('logs/clear',[LogController::class,'clear'])->name('logs.clear');});
